import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getOrders, deleteOrder } from './api';

function BasketList() {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    setOrders(getOrders());
  }, []);

  const handleDelete = (id) => {
    if (window.confirm('Точно удалить этот билет?')) {
      deleteOrder(id);
      setOrders(getOrders());
    }
  };

  return (
    <div className="crud-page">
      <div className="list-header">
        <h2>Ваша корзина</h2>
        <Link to="/create-order" className="add-btn">+ Добавить билет</Link>
      </div>

      {orders.length === 0 ? (
        <p>Корзина пуста.</p>
      ) : (
        <div className="order-list">
          {orders.map(order => (
            <div key={order.id} className="order-card">
              <div className="order-info">
                <h3>{order.title}</h3>
                <p>Цена: <strong>{order.price} сом</strong></p>
                <p>Клиент: {order.customer}</p>
              </div>
              <div className="order-actions">
                <Link to={`/basket/${order.id}`} className="view-btn">👀</Link>
                <Link to={`/update-order/${order.id}`} className="edit-btn">✏️</Link>
                <button onClick={() => handleDelete(order.id)} className="delete-btn">🗑</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default BasketList;
